#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/time.h>
#include <cuda_runtime.h>

struct Node_t0 {
    int starting;
    int no_of_edges;
};

static void Usage_t0(int argc, char** argv) {
    (void)argc;
    fprintf(stderr, "Usage: %s <num_threads> <input_file>\n", argv[0]);
}

static double omp_get_wtime_t0() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (double)tv.tv_sec + (double)tv.tv_usec * 1.0e-6;
}

__global__ void bfs_kernel1_t0(
    int no_of_nodes,
    Node_t0* graph_nodes,
    int* graph_edges,
    bool* graph_mask,
    bool* updating_graph_mask,
    bool* graph_visited,
    int* cost)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid < no_of_nodes && graph_mask[tid]) {
        graph_mask[tid] = false;
        int start = graph_nodes[tid].starting;
        int end = start + graph_nodes[tid].no_of_edges;
        int base_cost = cost[tid];
        for (int i = start; i < end; i++) {
            int id = graph_edges[i];
            if (!graph_visited[id]) {
                cost[id] = base_cost + 1;
                updating_graph_mask[id] = true;
            }
        }
    }
}

__global__ void bfs_kernel2_t0(
    int no_of_nodes,
    bool* graph_mask,
    bool* updating_graph_mask,
    bool* graph_visited,
    int* stop)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid < no_of_nodes && updating_graph_mask[tid]) {
        graph_mask[tid] = true;
        graph_visited[tid] = true;
        atomicExch(stop, 1);
        updating_graph_mask[tid] = false;
    }
}

static void BFSGraph_t0(int argc, char** argv) {
    int no_of_nodes = 0;
    int edge_list_size = 0;
    char* input_f;
    int num_omp_threads;

    if (argc != 3) {
        Usage_t0(argc, argv);
        exit(0);
    }

    num_omp_threads = atoi(argv[1]);
    (void)num_omp_threads;
    input_f = argv[2];

    printf("Reading File\n");

    FILE* fp = fopen(input_f, "r");
    if (!fp) {
        printf("Error Reading graph file\n");
        return;
    }

    int source = 0;
    fscanf(fp, "%d", &no_of_nodes);

    Node_t0* h_graph_nodes = (Node_t0*)malloc(sizeof(Node_t0) * (size_t)no_of_nodes);
    bool* h_graph_mask = (bool*)malloc(sizeof(bool) * (size_t)no_of_nodes);
    bool* h_updating_graph_mask = (bool*)malloc(sizeof(bool) * (size_t)no_of_nodes);
    bool* h_graph_visited = (bool*)malloc(sizeof(bool) * (size_t)no_of_nodes);

    int start, edgeno;
    for (unsigned int i = 0; i < (unsigned int)no_of_nodes; i++) {
        fscanf(fp, "%d %d", &start, &edgeno);
        h_graph_nodes[i].starting = start;
        h_graph_nodes[i].no_of_edges = edgeno;
        h_graph_mask[i] = false;
        h_updating_graph_mask[i] = false;
        h_graph_visited[i] = false;
    }

    fscanf(fp, "%d", &source);

    h_graph_mask[source] = true;
    h_graph_visited[source] = true;

    fscanf(fp, "%d", &edge_list_size);

    int id, cost;
    int* h_graph_edges = (int*)malloc(sizeof(int) * (size_t)edge_list_size);
    for (int i = 0; i < edge_list_size; i++) {
        fscanf(fp, "%d", &id);
        fscanf(fp, "%d", &cost);
        h_graph_edges[i] = id;
    }

    if (fp) {
        fclose(fp);
    }

    int* h_cost = (int*)malloc(sizeof(int) * (size_t)no_of_nodes);
    for (int i = 0; i < no_of_nodes; i++) {
        h_cost[i] = -1;
    }
    h_cost[source] = 0;

    printf("Start traversing the tree\n");

    Node_t0* d_graph_nodes = NULL;
    int* d_graph_edges = NULL;
    bool* d_graph_mask = NULL;
    bool* d_updating_graph_mask = NULL;
    bool* d_graph_visited = NULL;
    int* d_cost = NULL;
    int* d_stop = NULL;

    size_t nodes_bytes_node = (no_of_nodes > 0) ? sizeof(Node_t0) * (size_t)no_of_nodes : sizeof(Node_t0);
    size_t nodes_bytes_bool = (no_of_nodes > 0) ? sizeof(bool) * (size_t)no_of_nodes : sizeof(bool);
    size_t nodes_bytes_int = (no_of_nodes > 0) ? sizeof(int) * (size_t)no_of_nodes : sizeof(int);
    size_t edges_bytes = (edge_list_size > 0) ? sizeof(int) * (size_t)edge_list_size : sizeof(int);

    cudaMalloc((void**)&d_graph_nodes, nodes_bytes_node);
    cudaMalloc((void**)&d_graph_edges, edges_bytes);
    cudaMalloc((void**)&d_graph_mask, nodes_bytes_bool);
    cudaMalloc((void**)&d_updating_graph_mask, nodes_bytes_bool);
    cudaMalloc((void**)&d_graph_visited, nodes_bytes_bool);
    cudaMalloc((void**)&d_cost, nodes_bytes_int);
    cudaMalloc((void**)&d_stop, sizeof(int));

    if (no_of_nodes > 0) {
        cudaMemcpy(d_graph_nodes, h_graph_nodes, sizeof(Node_t0) * (size_t)no_of_nodes, cudaMemcpyHostToDevice);
        cudaMemcpy(d_graph_mask, h_graph_mask, sizeof(bool) * (size_t)no_of_nodes, cudaMemcpyHostToDevice);
        cudaMemcpy(d_updating_graph_mask, h_updating_graph_mask, sizeof(bool) * (size_t)no_of_nodes, cudaMemcpyHostToDevice);
        cudaMemcpy(d_graph_visited, h_graph_visited, sizeof(bool) * (size_t)no_of_nodes, cudaMemcpyHostToDevice);
        cudaMemcpy(d_cost, h_cost, sizeof(int) * (size_t)no_of_nodes, cudaMemcpyHostToDevice);
    }
    if (edge_list_size > 0) {
        cudaMemcpy(d_graph_edges, h_graph_edges, sizeof(int) * (size_t)edge_list_size, cudaMemcpyHostToDevice);
    }

    int k = 0;
    (void)k;
    double start_time = omp_get_wtime_t0();

    bool stop;
    int threads = 256;
    int blocks = (no_of_nodes + threads - 1) / threads;
    do {
        stop = false;
        int stop_int = 0;
        cudaMemcpy(d_stop, &stop_int, sizeof(int), cudaMemcpyHostToDevice);

        if (no_of_nodes > 0) {
            bfs_kernel1_t0<<<blocks, threads>>>(
                no_of_nodes,
                d_graph_nodes,
                d_graph_edges,
                d_graph_mask,
                d_updating_graph_mask,
                d_graph_visited,
                d_cost);

            bfs_kernel2_t0<<<blocks, threads>>>(
                no_of_nodes,
                d_graph_mask,
                d_updating_graph_mask,
                d_graph_visited,
                d_stop);
        }

        cudaMemcpy(&stop_int, d_stop, sizeof(int), cudaMemcpyDeviceToHost);
        stop = (stop_int != 0);
        k++;
    } while (stop);

    double end_time = omp_get_wtime_t0();
    printf("Compute time: %lf\n", (end_time - start_time));

    if (no_of_nodes > 0) {
        cudaMemcpy(h_cost, d_cost, sizeof(int) * (size_t)no_of_nodes, cudaMemcpyDeviceToHost);
    }

    FILE* fpo = fopen("result.txt", "w");
    for (int i = 0; i < no_of_nodes; i++) {
        fprintf(fpo, "%d) cost:%d\n", i, h_cost[i]);
    }
    fclose(fpo);
    printf("Result stored in result.txt\n");

    cudaFree(d_graph_nodes);
    cudaFree(d_graph_edges);
    cudaFree(d_graph_mask);
    cudaFree(d_updating_graph_mask);
    cudaFree(d_graph_visited);
    cudaFree(d_cost);
    cudaFree(d_stop);

    free(h_graph_nodes);
    free(h_graph_edges);
    free(h_graph_mask);
    free(h_updating_graph_mask);
    free(h_graph_visited);
    free(h_cost);
}

int main(int argc, char** argv) {
    BFSGraph_t0(argc, argv);
    return 0;
}

