                d_cost);

            bfs_kernel2_t2<<<blocks, threads>>>(
                no_of_nodes,
                d_graph_mask,
                d_updating_graph_mask,
                d_graph_visited,
                d_stop);
        }

        cudaMemcpy(&stop_int, d_stop, sizeof(int), cudaMemcpyDeviceToHost);
        stop = (stop_int != 0);
        k++;
    } while (stop);

    double end_time = omp_get_wtime_t2();
    printf("Compute time: %lf\n", (end_time - start_time));

    if (no_of_nodes > 0) {
        cudaMemcpy(h_cost, d_cost, sizeof(int) * (size_t)no_of_nodes, cudaMemcpyDeviceToHost);
    }

    FILE* fpo = fopen("result.txt", "w");
    for (int i = 0; i < no_of_nodes; i++) {
        fprintf(fpo, "%d) cost:%d\n", i, h_cost[i]);
    }
    fclose(fpo);
    printf("Result stored in result.txt\n");

    cudaFree(d_graph_nodes);
    cudaFree(d_graph_edges);
    cudaFree(d_graph_mask);
    cudaFree(d_updating_graph_mask);
    cudaFree(d_graph_visited);
    cudaFree(d_cost);
    cudaFree(d_stop);

    free(h_graph_nodes);
    free(h_graph_edges);
    free(h_graph_mask);
    free(h_updating_graph_mask);
    free(h_graph_visited);
    free(h_cost);
}

int __attribute__((weak)) main(int argc, char** argv) {
    BFSGraph_t2(argc, argv);
    return 0;
}
